61	export function createClaimRepository(db: Db) {
62	  return {
63	    db,
64	
65	    insertClaim(c: NewClaim): string {
66	      const id = randomUUID(); // status defaults to SUBMITTED; aggregated status set later
67	      db.insert(claims)
68	        .values({
69	          id,
70	          memberId: c.memberId,
71	          policyId: c.policyId,
72	          serviceDate: c.serviceDate,
73	          // provider/diagnosis_code are PHI — encrypted at rest (null stays null).
74	          provider: encryptPhiNullable(c.provider),
75	          diagnosisCode: encryptPhiNullable(c.diagnosisCode),
76	        })
77	        .run();
78	      return id;
79	    },
80	
81	    insertLine(claimId: string, l: NewLine): PersistedLine {
82	      const id = randomUUID(); // status defaults to PENDING
83	      const units = l.units ?? 1;
84	      const priorAuthPresent = l.priorAuthPresent ?? true;
85	      db.insert(lineItems)
86	        .values({
87	          id,
88	          claimId,
89	          serviceCode: l.serviceCode,
90	          billedCents: l.billedCents,
91	          units,
92	          priorAuthPresent,
93	          fingerprint: l.fingerprint,
94	        })
95	        .run();
96	      return {
97	        id,
98	        serviceCode: l.serviceCode,
99	        billedCents: l.billedCents,
100	        units,
101	        priorAuthPresent,
102	        fingerprint: l.fingerprint,
103	      };
104	    },
105	
106	    setLineStatus(lineItemId: string, status: LineItemStatus): void {
107	      db.update(lineItems)
108	        .set({ status })
109	        .where(eq(lineItems.id, lineItemId))
110	        .run();
111	    },
112	
113	    setClaimStatus(claimId: string, status: ClaimStatus): void {
114	      db.update(claims).set({ status }).where(eq(claims.id, claimId)).run();
115	    },
116	
117	    // Advance the claim's logical clock (the head for status_transitions.seq) and return it.
118	    bumpClaimSeq(claimId: string): number {
119	      const row = db
120	        .select({ seq: claims.claimSeq })
121	        .from(claims)
122	        .where(eq(claims.id, claimId))
123	        .get();
124	      const next = (row?.seq ?? 0) + 1;
125	      db.update(claims)
126	        .set({ claimSeq: next })
127	        .where(eq(claims.id, claimId))
128	        .run();
129	      return next;
130	    },
131	
132	    findLineById(id: string): LineRecord | undefined {
133	      const row = db.select().from(lineItems).where(eq(lineItems.id, id)).get();
134	      if (!row) return undefined;
