153	        policyId: row.policyId,
154	        serviceDate: row.serviceDate,
155	        status: row.status,
156	      };
157	    },
158	
159	    // Decrypt a claim's PHI (provider/diagnosis). Separate from findClaimById so PHI is read only
160	    // when explicitly needed — never on the hot adjudication/read path.
161	    findClaimPhi(id: string): ClaimPhi | undefined {
162	      const row = db
163	        .select({
164	          provider: claims.provider,
165	          diagnosisCode: claims.diagnosisCode,
166	        })
167	        .from(claims)
168	        .where(eq(claims.id, id))
169	        .get();
