import Database from 'better-sqlite3';
import { decryptPhi } from './app/src/db/phi-crypto';
const db=new Database('./claims.db');
const r:any=db.prepare(\"select id,provider,diagnosis_code from claims where provider is not null order by created_at desc limit 1\").get();
if(r){console.log('on-disk ciphertext starts g1: ->', r.provider.startsWith('g1:'));
