import { createDb } from './app/src/db/connection';
import { applySchema } from './app/src/db/migrate';
import { seed } from './app/src/db/seed';
import { createClaimRepository } from './app/src/repositories/claim.repository';
import Database from 'better-sqlite3';

const { db, sqlite } = createDb('./claims.db');
applySchema(sqlite); seed(db);
const repo = createClaimRepository(db);
const id = repo.insertClaim({ memberId:'mem_approved', policyId:'pol_mem_approved', serviceDate:'2026-03-01', provider:'Acme Hospital', diagnosisCode:'E11.9' });

// read RAW bytes straight from the column (bypass the repo's decrypt)
const raw:any = sqlite.prepare('select provider, diagnosis_code from claims where id=?').get(id);
console.log('RAW provider on disk :', raw.provider);
console.log('RAW diagnosis on disk:', raw.diagnosis_code);
console.log('ciphertext? (g1, no plaintext):', raw.provider.startsWith('g1:') && !raw.provider.includes('Acme'));

// read back through the repo's decrypt accessor
console.log('decrypted via findClaimPhi:', JSON.stringify(repo.findClaimPhi(id)));
"
